import Image from "next/image";

// constants
const works = [
  {
    title: "First one",
    description: "At half-past eight",
    image: "https://cdn.uiable.com/block/g1.jpg",
  },
  {
    title: "Second one",
    description: "At half-past eight",
    image: "https://cdn.uiable.com/block/g2.jpg",
  },
  {
    title: "Third one",
    description: "At half-past eight",
    image: "https://cdn.uiable.com/block/g3.jpg",
  },
  {
    title: "Four one",
    description: "At half-past eight",
    image: "https://cdn.uiable.com/block/g4.jpg",
  },
];

//  ------------------------------ | GALLERY 9 | ------------------------------  //

export default function Gallery8() {
  return (
    <section className="py-16 md:py-24">
      <div className="container px-4 mx-auto">
        <div className="grid grid-cols-12 gap-y-12 text-center">
          {/* Header Section */}
          <div className="col-span-12 flex flex-col items-center gap-4">
            <h2>Our Works</h2>
            <p className="text-slate-500 text-sm md:text-base max-w-2xl">
              At half-past eight the door opened, the policeman appeared and
              requesting them to follow him, led way to an adjoining hall.
            </p>
          </div>

          {/* Gallery Items Grid */}
          <div className="col-span-12">
            <div className="grid grid-cols-12 gap-y-6 md:gap-x-6">
              {works.map((item, index) => (
                <div
                  key={index}
                  className="col-span-12 sm:col-span-6 md:col-span-3 flex flex-col items-center gap-6"
                >
                  {/* Circular Image Container */}
                  <div className="relative w-full max-w-50 aspect-square rounded-full overflow-hidden border border-slate-100 shadow-sm">
                    <Image
                      src={item.image}
                      alt={item.title}
                      fill
                      className="object-cover"
                    />
                  </div>

                  {/* Text Content */}
                  <div className="flex flex-col gap-1">
                    <h4>{item.title}</h4>
                    <p className="text-slate-500 text-sm md:text-md">
                      {item.description}
                    </p>
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>
    </section>
  );
}
